}

// -----------------------------------------------------------------------
// FIGMA DRAWER CONTENT (stranski meni)
// -----------------------------------------------------------------------
@Composable
fun FigmaDrawerContent(
    userProfile: UserProfile,
    onClose: () -> Unit,
    onLogout: () -> Unit,
    onProfileUpdate: (UserProfile) -> Unit,
    isDarkMode: Boolean,
    onDarkModeToggle: () -> Unit,
    onNavigateToPrivacyPolicy: () -> Unit,
    onNavigateToTermsOfService: () -> Unit,
    onNavigateToContact: () -> Unit,
    onNavigateToAbout: () -> Unit,
    onNavigateToAchievements: () -> Unit = {},
    onNavigateToBadges: () -> Unit = {},
    onNavigateToHealthConnect: () -> Unit = {},
    onNavigateToDebugDashboard: () -> Unit = {},
    onNavigateToMyAccount: () -> Unit
) {
    val PrimaryBlue = MaterialTheme.colorScheme.primary
    val SheetBg = MaterialTheme.colorScheme.surface
    val CardBg = MaterialTheme.colorScheme.surfaceVariant
    val TextPrimary = MaterialTheme.colorScheme.onSurface
    val TextSecondary = MaterialTheme.colorScheme.onSurfaceVariant
    val context = LocalContext.current

    var isEditingPersonal by remember { mutableStateOf(false) }
    var editedProfile by remember { mutableStateOf(userProfile) }
    var showEquipmentDialog by remember { mutableStateOf(false) }
    var isPublicPrivacy by remember { mutableStateOf(userProfile.isPublicProfile) }
    var showLevelPrivacy by remember { mutableStateOf(userProfile.showLevel) }
    var showBadgesPrivacy by remember { mutableStateOf(userProfile.showBadges) }
    var showPlanPathPrivacy by remember { mutableStateOf(userProfile.showPlanPath) }
    var showChallengesPrivacy by remember { mutableStateOf(userProfile.showChallenges) }
    var showFollowersPrivacy by remember { mutableStateOf(userProfile.showFollowers) }
    var shareActivitiesPrivacy by remember { mutableStateOf(userProfile.shareActivities) }

    // Debug Dashboard — 5-kratni klik na stickman avatar
    var debugClickCount by remember { mutableIntStateOf(0) }
    var lastDebugClickTime by remember { mutableLongStateOf(0L) }

    LaunchedEffect(userProfile) {
        editedProfile = userProfile
        isPublicPrivacy = userProfile.isPublicProfile
        showLevelPrivacy = userProfile.showLevel
        showBadgesPrivacy = userProfile.showBadges
        showPlanPathPrivacy = userProfile.showPlanPath
        showChallengesPrivacy = userProfile.showChallenges
        showFollowersPrivacy = userProfile.showFollowers
        shareActivitiesPrivacy = userProfile.shareActivities
    }

    Surface(
        color = SheetBg,
        modifier = Modifier.fillMaxHeight().width(320.dp)
    ) {
        Column(
            modifier = Modifier
                .fillMaxSize()
                .verticalScroll(rememberScrollState())
                .padding(horizontal = 16.dp, vertical = 12.dp)
        ) {
            // Gumb za zaprtje
            Row(
                verticalAlignment = Alignment.CenterVertically,
                modifier = Modifier
                    .fillMaxWidth()
                    .windowInsetsPadding(WindowInsets.safeDrawing.only(WindowInsetsSides.Top))
            ) {
                TextButton(onClick = onClose) { Text("← Back", color = TextPrimary) }
                Spacer(Modifier.weight(1f))
            }

            // 1. Stickman avatar — 5-klik aktivira Debug Dashboard
            Surface(
                color = PrimaryBlue,
                shape = MaterialTheme.shapes.large,
                modifier = Modifier
                    .fillMaxWidth()
                    .heightIn(min = 160.dp)
                    .padding(vertical = 8.dp)
                    .clickable {
                        val now = System.currentTimeMillis()
                        if (now - lastDebugClickTime > 1500) {
                            // Preveč časa med kliki — resetiraj števec
                            debugClickCount = 1
                        } else {
                            debugClickCount++
                        }
                        lastDebugClickTime = now
                        if (debugClickCount >= 5) {
                            debugClickCount = 0
                            onNavigateToDebugDashboard()
                        }
                    }
            ) {
                Box(contentAlignment = Alignment.Center, modifier = Modifier.fillMaxSize()) {
                    Icon(
                        painter = painterResource(id = R.drawable.ic_muscular_stickman),
                        contentDescription = "Stickman Avatar",
                        tint = MaterialTheme.colorScheme.onPrimary,
                        modifier = Modifier.size(100.dp).padding(16.dp)
                    )
                    // Indikator napredka klikov (prikaže se po 2. kliku)
                    if (debugClickCount in 2..4) {
                        Box(
                            modifier = Modifier
                                .align(Alignment.BottomEnd)
                                .padding(8.dp)
                                .background(
                                    color = MaterialTheme.colorScheme.onPrimary.copy(alpha = 0.2f),
                                    shape = MaterialTheme.shapes.small
                                )
                                .padding(horizontal = 6.dp, vertical = 2.dp)
                        ) {
                            Text(
                                "$debugClickCount/5",
                                color = MaterialTheme.colorScheme.onPrimary,
                                fontSize = 11.sp,
                                fontWeight = FontWeight.Bold
                            )
                        }
                    }
                }
            }

            Spacer(Modifier.height(12.dp))

            // 2. Stats (Level, XP, Followers, Badges)
            Card(
                colors = CardDefaults.cardColors(containerColor = CardBg),
                shape = MaterialTheme.shapes.large,
                modifier = Modifier.fillMaxWidth().shadow(8.dp, MaterialTheme.shapes.large).clickable { onNavigateToAchievements() }
            ) {
                Column(modifier = Modifier.padding(16.dp)) {
                    // Level & XP header
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .background(PrimaryBlue.copy(alpha = 0.1f), MaterialTheme.shapes.medium)
                            .padding(12.dp),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Column {
                            Text("LEVEL", color = TextSecondary, fontSize = 11.sp, fontWeight = FontWeight.Bold)
                            Text("${userProfile.level}", color = PrimaryBlue, fontSize = 32.sp, fontWeight = FontWeight.ExtraBold)
                        }
