@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun SettingsDropdownRow(
    label: String,
    currentValue: String,
    options: List<String>,
    textColor: Color,
    onValueChange: (String) -> Unit
) {
    var expanded by remember { mutableStateOf(false) }
    Row(
        modifier = Modifier.fillMaxWidth().padding(vertical = 8.dp),
        horizontalArrangement = Arrangement.SpaceBetween,
        verticalAlignment = Alignment.CenterVertically
    ) {
        Text(label, style = MaterialTheme.typography.bodyMedium, color = textColor)
        Box(modifier = Modifier.wrapContentSize(Alignment.TopStart)) {
            Row(
                modifier = Modifier.clip(RoundedCornerShape(8.dp))
                    .border(1.dp, textColor.copy(alpha = 0.5f), RoundedCornerShape(8.dp))
                    .clickable { expanded = true }
                    .padding(horizontal = 12.dp, vertical = 8.dp),
                verticalAlignment = Alignment.CenterVertically
            ) {
                Text(currentValue, style = MaterialTheme.typography.bodyMedium, color = textColor)
                Spacer(modifier = Modifier.width(8.dp))
                Icon(Icons.Filled.ExpandMore, "Expand", tint = textColor)
            }
            DropdownMenu(expanded = expanded, onDismissRequest = { expanded = false }) {
                options.forEach { option ->
                    DropdownMenuItem(
                        text = {
                            Text(option, style = MaterialTheme.typography.bodyMedium,
                                fontWeight = if (option == currentValue) FontWeight.Bold else FontWeight.Normal)
                        },
                        onClick = { expanded = false; onValueChange(option) },
                        contentPadding = PaddingValues(16.dp)
                    )
                }
            }
        }
    }
}

// -----------------------------------------------------------------------
// POMOŽNA FUNKCIJA: izračuna avtomatsko odklenjene badge-e iz userProfile
// Vrne Pair(Set<String> odklenjenih ID-jev, Int skupaj)
// Badge zahteve so definirane SAMO v BadgeDefinitions.ALL_BADGES (badge.requirement).
// -----------------------------------------------------------------------
fun calculateAutoUnlockedBadgeCount(userProfile: UserProfile): Pair<Set<String>, Int> {
    val repo = com.example.myapplication.data.gamification.FirestoreGamificationRepository()
    val useCase = com.example.myapplication.domain.gamification.ManageGamificationUseCase(repo)
    // Pretvori data.UserProfile → domain.model.AchievementProfile (Clean Architecture mapping)
    val profile = com.example.myapplication.domain.model.AchievementProfile(
        totalWorkoutsCompleted = userProfile.totalWorkoutsCompleted,
        totalCaloriesBurned    = userProfile.totalCaloriesBurned,
        level                  = userProfile.level,
        followers              = userProfile.followers,
        earlyBirdWorkouts      = userProfile.earlyBirdWorkouts,
        nightOwlWorkouts       = userProfile.nightOwlWorkouts,
        currentLoginStreak     = userProfile.currentLoginStreak,
        totalPlansCreated      = userProfile.totalPlansCreated
    )
    val ids = com.example.myapplication.data.BadgeDefinitions.ALL_BADGES
        .filter { badge ->
            useCase.getBadgeProgress(badge.id, profile) >= badge.requirement
        }
        .map { it.id }
        .toSet()
    return Pair(ids, ids.size)
}

package com.example.myapplication.data.gamification

import android.util.Log
import com.example.myapplication.data.UserProfile
import com.example.myapplication.domain.gamification.GamificationRepository
import com.example.myapplication.persistence.FirestoreHelper
import com.google.firebase.firestore.SetOptions
import kotlinx.coroutines.tasks.await
import kotlinx.datetime.Clock
import kotlinx.datetime.TimeZone
import kotlinx.datetime.toLocalDateTime

/**
 * Zlata koda - KMP ready Firestore implementacija za Gamification.
 * NIMA NITI ENE SharedPreferences ODVISNOSTI.
 *
 * Faza 4b: dailyHistory mapa v glavnem doc (ne subcollection daily_logs).
 * Streak +1 za Workout, +1 za Stretching (Rest day), 0 za Freeze, =0 brez freeze-a.
 * checkIfFutureRestDaysExistAndSwap je IZBRISAN — auto-swap ni več potreben.
 */
class FirestoreGamificationRepository : GamificationRepository {

    private val db get() = FirestoreHelper.getDb()

    private fun getTodayStr(): String {
        return Clock.System.now().toLocalDateTime(TimeZone.currentSystemDefault()).date.toString()
    }

    private fun getYesterdayStr(): String {
        val yesterdayMillis = Clock.System.now().toEpochMilliseconds() - 86400000L
        return kotlinx.datetime.Instant.fromEpochMilliseconds(yesterdayMillis)
            .toLocalDateTime(TimeZone.currentSystemDefault()).date.toString()
    }

    override suspend fun awardXP(amount: Int, reason: String) {
        val userRef = FirestoreHelper.getCurrentUserDocRef() ?: return

        try {
            db.runTransaction { transaction ->
                val snapshot = transaction.get(userRef)

                // Atomarno branje trenutnega XP in izračun novega nivoja — vse znotraj transakcije
                val currentXp = snapshot.getLong("xp")?.toInt() ?: 0
                val newXp = currentXp + amount
                // Level je izračunan znotraj transakcije — atomarno posodabljamo xp IN level hkrati
                val newLevel = UserProfile.calculateLevel(newXp)

                // Posodobi xp + level atomarno (set+merge varno za obstoječ in NOV dokument)
                transaction.set(userRef, mapOf(
                    "xp"    to newXp,
                    "level" to newLevel
                ), SetOptions.merge())

                // Log v podzbirko xp_history (znotraj iste transakcije)
                val logRef = userRef.collection("xp_history").document()
                transaction.set(logRef, mapOf(
                    "amount"    to amount,
                    "reason"    to reason,
                    "date"      to getTodayStr(),
                    "timestamp" to Clock.System.now().toEpochMilliseconds(),
                    "xpAfter"   to newXp,
                    "levelAfter" to newLevel
                ))
            }.await()
            Log.d("GamificationRepo", "✅ Dodeljeno $amount XP za '$reason'")
        } catch (e: Exception) {
            Log.e("GamificationRepo", "Napaka pri beleženju XP-ja", e)
        }
    }

    override suspend fun getCurrentStreak(): Int {
        val userRef = FirestoreHelper.getCurrentUserDocRef() ?: return 0
        try {
            val snapshot = userRef.get().await()
            return snapshot.getLong("streak_days")?.toInt() ?: 0
        } catch (e: Exception) {
            return 0
        }
    }

    /**
     * Faza 4b — Nova Streak logika (Daily Habit):
     * +1 za workout DAN in uspešen trening.
     * +1 za rest DAN in opravljeno raztezanje (activityType = "STRETCHING_DONE").
     * De-dup: dailyHistory mapa v glavnem dokumentu (hitrejše branje, brez subcollection).
     * @return Novi streak po posodobitvi (0 ob napaki)
     */
    override suspend fun updateStreak(isWorkoutSuccess: Boolean, activityType: String): Int {
        val userRef = FirestoreHelper.getCurrentUserDocRef() ?: return 0
        val todayStr = getTodayStr()

        return try {
            var computedStreak = 0
            db.runTransaction { transaction ->
                val snapshot = transaction.get(userRef)

                // De-dup: preveri dailyHistory mapo v glavnem dokumentu
                @Suppress("UNCHECKED_CAST")
                val dailyHistory = (snapshot.get("dailyHistory") as? Map<String, Any>) ?: emptyMap()
                if (dailyHistory.containsKey(todayStr)) {
                    val existingStatus = dailyHistory[todayStr]?.toString() ?: "?"
                    Log.d("GamificationRepo", "Danes že zabeleženo kot $existingStatus — preskočim.")
                    computedStreak = snapshot.getLong("streak_days")?.toInt() ?: 0
                    return@runTransaction null
                }

                val currentStreak = snapshot.getLong("streak_days")?.toInt() ?: 0
                // Streak +1 samo ob uspešnem dnevu (workout ali stretching)
                val newStreak = if (isWorkoutSuccess) currentStreak + 1 else currentStreak
                computedStreak = newStreak

                // Zapiši streak + dailyHistory.$todayStr — vse v enem update()
                // Dot notation v update() = nested field path (Firestore standard)
                transaction.update(userRef, mapOf(
                    "streak_days" to newStreak,
                    "last_streak_update_date" to todayStr,
                    "dailyHistory.$todayStr" to activityType
                ))
                null
            }.await()
            Log.d("GamificationRepo", "✅ Streak posodobljen: $computedStreak ($activityType)")
            computedStreak
        } catch (e: Exception) {
            Log.e("GamificationRepo", "Napaka pri posodabljanju streaka.", e)
            0
        }
    }

    /**
     * Označi TODAY kot "PENDING_STRETCHING" — brez streak +1.
     * Proži se ko app ugotovi da je danes rest day, preden uporabnik sproži raztezanje.
     * Deluje kot idempoten write: če je dan že zabeležen (STRETCHING_DONE), ga ne prepiše.
     */
    override suspend fun markRestDayPending() {
        val userRef = FirestoreHelper.getCurrentUserDocRef() ?: return
        val todayStr = getTodayStr()
        try {
            db.runTransaction { transaction ->
                val snapshot = transaction.get(userRef)
                @Suppress("UNCHECKED_CAST")
                val dailyHistory = (snapshot.get("dailyHistory") as? Map<String, Any>) ?: emptyMap()

                // Ne prepiši, če je dan STRETCHING_DONE ali WORKOUT_DONE (že zaključen)
                val existing = dailyHistory[todayStr]?.toString()
                if (existing == "STRETCHING_DONE" || existing == "WORKOUT_DONE") {
                    Log.d("GamificationRepo", "Rest day $todayStr že zaključen ($existing) — preskočim pending.")
                    return@runTransaction null
                }

                // Zapiši PENDING_STRETCHING samo z dot-notation (ne poveča streak_days)
                transaction.update(userRef, mapOf(
                    "dailyHistory.$todayStr" to "PENDING_STRETCHING"
                ))
                null
            }.await()
            Log.d("GamificationRepo", "✅ Rest day $todayStr → PENDING_STRETCHING")
        } catch (e: Exception) {
            Log.e("GamificationRepo", "Napaka pri markRestDayPending()", e)
        }
    }

    /**
     * Faza 8 — Unified Streak Engine (nadomešča UserProfileManager.updateUserProgressAfterWorkout).
     *
     * Atomarna Firestore transakcija:
     * 1. De-dup: če danes že WORKOUT_DONE → preskoči
     * 2. Epoch-based streak: dayDiff == 1 → +1, gap → freeze check
     * 3. Zapiše dailyHistory.$today = "WORKOUT_DONE"
     * 4. Posodobi streak_days, plan_day, last_workout_epoch, streak_freezes (če porabljen)
     */
    override suspend fun processWorkoutCompletion(incrementPlanDay: Boolean) {
        val userRef = FirestoreHelper.getCurrentUserDocRef() ?: return
        val todayStr = getTodayStr()
        val todayEpoch: Long = Clock.System.now()
            .toLocalDateTime(TimeZone.currentSystemDefault())
            .date.toEpochDays().toLong()

        try {
            db.runTransaction { transaction ->
                val snapshot = transaction.get(userRef)

                // De-dup: danes že zabeležen kot WORKOUT_DONE → preskoči
                @Suppress("UNCHECKED_CAST")
                val dailyHistory = (snapshot.get("dailyHistory") as? Map<String, Any>) ?: emptyMap()
                if (dailyHistory[todayStr] == "WORKOUT_DONE") {
                    Log.d("GamificationRepo", "processWorkoutCompletion: danes že WORKOUT_DONE — preskočim.")
                    return@runTransaction null
                }

                val oldStreak    = (snapshot.getLong("streak_days")        ?: 0L).toInt()
                val oldLastEpoch =  snapshot.getLong("last_workout_epoch") ?: 0L
                val oldPlanDay   = (snapshot.getLong("plan_day")           ?: 1L).toInt()
                val oldFreezes   = (snapshot.getLong("streak_freezes")     ?: 0L).toInt()

                // Plan day: +1 samo za redne workouty
                val newPlanDay = if (incrementPlanDay) oldPlanDay + 1 else oldPlanDay

                // Epoch-based streak izračun z Streak Freeze podporo
                val dayDiff = todayEpoch - oldLastEpoch
                var newFreezes = oldFreezes
                val newStreak = when {
                    oldLastEpoch == 0L -> 1              // prvi trening kdajkoli
                    dayDiff == 0L      -> oldStreak      // danes že treniral (via drug update) — ohrani
                    dayDiff == 1L      -> oldStreak + 1  // včeraj → podaljšaj
                    else -> {
                        // Prekinitev — preveri zamrznitve (Streak Freeze)
                        if (oldFreezes > 0) {
                            newFreezes = oldFreezes - 1
                            Log.d("GamificationRepo", "❄️ Streak Freeze porabljen! Ostalo: $newFreezes")
                            oldStreak  // streak se ohrani, NE poveča
                        } else {
                            1          // ni zamrznitev → ponastavi na 1
                        }
                    }
                }

                val updates = mutableMapOf<String, Any>(
                    "streak_days"              to newStreak,
                    "plan_day"                 to newPlanDay,
                    "last_workout_epoch"       to todayEpoch,
                    "last_streak_update_date"  to todayStr,
                    "dailyHistory.$todayStr"   to "WORKOUT_DONE"
                )
                if (newFreezes != oldFreezes) {
                    updates["streak_freezes"] = newFreezes
                }

                transaction.update(userRef, updates)
                Log.d("GamificationRepo", "✅ processWorkoutCompletion: streak=$newStreak, planDay=$newPlanDay, " +
                    "incrementPlanDay=$incrementPlanDay, freezeUsed=${newFreezes != oldFreezes}")
                null
            }.await()
        } catch (e: Exception) {
            Log.e("GamificationRepo", "❌ processWorkoutCompletion failed: ${e.message}", e)
        }
    }

    /**
     * Vrni status današnjega dne iz dailyHistory mape.
     */
    override suspend fun getTodayStatus(): String? {
        val userRef = FirestoreHelper.getCurrentUserDocRef() ?: return null
        return try {
            val snapshot = userRef.get().await()
            @Suppress("UNCHECKED_CAST")
            val dailyHistory = (snapshot.get("dailyHistory") as? Map<String, Any>) ?: emptyMap()
            dailyHistory[getTodayStr()]?.toString()
        } catch (e: Exception) {
            Log.e("GamificationRepo", "getTodayStatus failed", e)
            null
        }
    }

    override suspend fun consumeStreakFreeze(): Boolean {
        val userRef = FirestoreHelper.getCurrentUserDocRef() ?: return false
        return try {
            var freezeConsumed = false
            db.runTransaction { transaction ->
                val snapshot = transaction.get(userRef)
                val currentFreezes = snapshot.getLong("streak_freezes")?.toInt() ?: 0

                if (currentFreezes > 0) {
                    transaction.update(userRef, "streak_freezes", currentFreezes - 1)
                    freezeConsumed = true
                }
            }.await()
            freezeConsumed
        } catch (e: Exception) {
             false
        }
    }

    /**
     * Faza 4b — Polnočni streak check (brez auto-swap logike).
     *
     * Pravila:
     * - Dan je zabeležen v dailyHistory mapi → ni akcije.
     * - Dan ni zabeležen + ima freeze → auto-porabi freeze, zapiši "FROZEN".
     * - Dan ni zabeležen + ni freeze → streak = 0, zapiši "MISSED".
     *
     * checkIfFutureRestDaysExistAndSwap() je IZBRISAN (Faza 4b).
     */
    override suspend fun runMidnightStreakCheck() {
        val userRef = FirestoreHelper.getCurrentUserDocRef() ?: return
        val yesterdayStr = getYesterdayStr()

        try {
            db.runTransaction { transaction ->
                val snapshot = transaction.get(userRef)

                // Preveri dailyHistory mapo v glavnem dokumentu
                @Suppress("UNCHECKED_CAST")
                val dailyHistory = (snapshot.get("dailyHistory") as? Map<String, Any>) ?: emptyMap()

                if (dailyHistory.containsKey(yesterdayStr)) {
                    // Včeraj je bil uspešno zabeležen — ni akcije
                    Log.d("GamificationRepo", "Včeraj ($yesterdayStr) zabeležen: ${dailyHistory[yesterdayStr]}")
                    return@runTransaction null
                }

                // Včerajšnji dan ni bil opravljen
                val currentFreezes = (snapshot.getLong("streak_freezes") ?: 0L).toInt()

                if (currentFreezes > 0) {
                    // Auto-porabi Streak Freeze
                    transaction.update(userRef, mapOf(
                        "streak_freezes" to (currentFreezes - 1),
                        "dailyHistory.$yesterdayStr" to "FROZEN"
                    ))
                    Log.d("GamificationRepo", "❄️ Streak Freeze auto-porabljen. Ostalo: ${currentFreezes - 1}")
                } else {
                    // Ni freeze-a → streak pade na 0
                    transaction.update(userRef, mapOf(
                        "streak_days" to 0,
                        "dailyHistory.$yesterdayStr" to "MISSED"
                    ))
                    Log.d("GamificationRepo", " Ni freeze-a. Streak je padel na 0.")
                }
                null
            }.await()
        } catch (e: Exception) {
            Log.e("GamificationRepo", "Polnočni streak check je spodletel.", e)
        }
    }

}

package com.example.myapplication.data.gamification

import android.util.Log
import com.example.myapplication.data.UserProfile
import com.example.myapplication.domain.gamification.GamificationRepository
import com.example.myapplication.domain.gamification.GamificationState
import com.example.myapplication.persistence.FirestoreHelper
import com.google.firebase.firestore.SetOptions
import kotlinx.coroutines.tasks.await
import kotlinx.datetime.Clock
import kotlinx.datetime.TimeZone
import kotlinx.datetime.toLocalDateTime

/**
 * Zlata koda - KMP ready Firestore implementacija za Gamification.
 * NIMA NITI ENE SharedPreferences ODVISNOSTI.
 *
 * Faza 4b: dailyHistory mapa v glavnem doc (ne subcollection daily_logs).
 * Streak +1 za Workout, +1 za Stretching (Rest day), 0 za Freeze, =0 brez freeze-a.
 * checkIfFutureRestDaysExistAndSwap je IZBRISAN — auto-swap ni več potreben.
 */
class FirestoreGamificationRepository : GamificationRepository {

    private val db get() = FirestoreHelper.getDb()

    private fun getTodayStr(): String {
        return Clock.System.now().toLocalDateTime(TimeZone.currentSystemDefault()).date.toString()
    }

    private fun getYesterdayStr(): String {
        val yesterdayMillis = Clock.System.now().toEpochMilliseconds() - 86400000L
        return kotlinx.datetime.Instant.fromEpochMilliseconds(yesterdayMillis)
            .toLocalDateTime(TimeZone.currentSystemDefault()).date.toString()
    }

    override suspend fun awardXP(amount: Int, reason: String) {
        val userRef = FirestoreHelper.getCurrentUserDocRef() ?: return

        try {
            db.runTransaction { transaction ->
                val snapshot = transaction.get(userRef)

                // Atomarno branje trenutnega XP in izračun novega nivoja — vse znotraj transakcije
                val currentXp = snapshot.getLong("xp")?.toInt() ?: 0
                val newXp = currentXp + amount
                // Level je izračunan znotraj transakcije — atomarno posodabljamo xp IN level hkrati
                val newLevel = UserProfile.calculateLevel(newXp)

                // Posodobi xp + level atomarno (set+merge varno za obstoječ in NOV dokument)
                transaction.set(userRef, mapOf(
                    "xp"    to newXp,
                    "level" to newLevel
                ), SetOptions.merge())

                // Log v podzbirko xp_history (znotraj iste transakcije)
                val logRef = userRef.collection("xp_history").document()
                transaction.set(logRef, mapOf(
                    "amount"    to amount,
                    "reason"    to reason,
                    "date"      to getTodayStr(),
                    "timestamp" to Clock.System.now().toEpochMilliseconds(),
                    "xpAfter"   to newXp,
                    "levelAfter" to newLevel
                ))
            }.await()
            Log.d("GamificationRepo", "✅ Dodeljeno $amount XP za '$reason'")
        } catch (e: Exception) {
            Log.e("GamificationRepo", "Napaka pri beleženju XP-ja", e)
        }
    }

    override suspend fun getCurrentStreak(): Int {
        val userRef = FirestoreHelper.getCurrentUserDocRef() ?: return 0
        try {
            val snapshot = userRef.get().await()
            return snapshot.getLong("streak_days")?.toInt() ?: 0
        } catch (e: Exception) {
            return 0
        }
    }

    /**
     * Faza 4b — Nova Streak logika (Daily Habit):
     * +1 za workout DAN in uspešen trening.
     * +1 za rest DAN in opravljeno raztezanje (activityType = "STRETCHING_DONE").
     * De-dup: dailyHistory mapa v glavnem dokumentu (hitrejše branje, brez subcollection).
     * @return Novi streak po posodobitvi (0 ob napaki)
     */
    override suspend fun updateStreak(isWorkoutSuccess: Boolean, activityType: String): Int {
        val userRef = FirestoreHelper.getCurrentUserDocRef() ?: return 0
        val todayStr = getTodayStr()

        return try {
            var computedStreak = 0
            db.runTransaction { transaction ->
                val snapshot = transaction.get(userRef)

                // De-dup: preveri dailyHistory mapo v glavnem dokumentu
                @Suppress("UNCHECKED_CAST")
                val dailyHistory = (snapshot.get("dailyHistory") as? Map<String, Any>) ?: emptyMap()
                if (dailyHistory.containsKey(todayStr)) {
                    val existingStatus = dailyHistory[todayStr]?.toString() ?: "?"
                    Log.d("GamificationRepo", "Danes že zabeleženo kot $existingStatus — preskočim.")
                    computedStreak = snapshot.getLong("streak_days")?.toInt() ?: 0
                    return@runTransaction null
                }

                val currentStreak = snapshot.getLong("streak_days")?.toInt() ?: 0
                // Streak +1 samo ob uspešnem dnevu (workout ali stretching)
                val newStreak = if (isWorkoutSuccess) currentStreak + 1 else currentStreak
                computedStreak = newStreak

                // Zapiši streak + dailyHistory.$todayStr — vse v enem update()
                // Dot notation v update() = nested field path (Firestore standard)
                transaction.update(userRef, mapOf(
                    "streak_days" to newStreak,
                    "last_streak_update_date" to todayStr,
                    "dailyHistory.$todayStr" to activityType
                ))
                null
            }.await()
            Log.d("GamificationRepo", "✅ Streak posodobljen: $computedStreak ($activityType)")
            computedStreak
        } catch (e: Exception) {
            Log.e("GamificationRepo", "Napaka pri posodabljanju streaka.", e)
            0
        }
    }

    /**
     * Označi TODAY kot "PENDING_STRETCHING" — brez streak +1.
     * Proži se ko app ugotovi da je danes rest day, preden uporabnik sproži raztezanje.
     * Deluje kot idempoten write: če je dan že zabeležen (STRETCHING_DONE), ga ne prepiše.
     */
    override suspend fun markRestDayPending() {
        val userRef = FirestoreHelper.getCurrentUserDocRef() ?: return
        val todayStr = getTodayStr()
        try {
            db.runTransaction { transaction ->
                val snapshot = transaction.get(userRef)
                @Suppress("UNCHECKED_CAST")
                val dailyHistory = (snapshot.get("dailyHistory") as? Map<String, Any>) ?: emptyMap()

                // Ne prepiši, če je dan STRETCHING_DONE ali WORKOUT_DONE (že zaključen)
                val existing = dailyHistory[todayStr]?.toString()
                if (existing == "STRETCHING_DONE" || existing == "WORKOUT_DONE") {
                    Log.d("GamificationRepo", "Rest day $todayStr že zaključen ($existing) — preskočim pending.")
                    return@runTransaction null
                }

                // Zapiši PENDING_STRETCHING samo z dot-notation (ne poveča streak_days)
                transaction.update(userRef, mapOf(
                    "dailyHistory.$todayStr" to "PENDING_STRETCHING"
                ))
                null
            }.await()
            Log.d("GamificationRepo", "✅ Rest day $todayStr → PENDING_STRETCHING")
        } catch (e: Exception) {
            Log.e("GamificationRepo", "Napaka pri markRestDayPending()", e)
        }
    }

    /**
     * Faza 8 — Unified Streak Engine (nadomešča UserProfileManager.updateUserProgressAfterWorkout).
     *
     * Atomarna Firestore transakcija:
     * 1. De-dup: če danes že WORKOUT_DONE → preskoči
     * 2. Epoch-based streak: dayDiff == 1 → +1, gap → freeze check
     * 3. Zapiše dailyHistory.$today = "WORKOUT_DONE"
     * 4. Posodobi streak_days, plan_day, last_workout_epoch, streak_freezes (če porabljen)
     */
    override suspend fun processWorkoutCompletion(incrementPlanDay: Boolean) {
        val userRef = FirestoreHelper.getCurrentUserDocRef() ?: return
        val todayStr = getTodayStr()
        val todayEpoch: Long = Clock.System.now()
            .toLocalDateTime(TimeZone.currentSystemDefault())
            .date.toEpochDays().toLong()

        try {
            db.runTransaction { transaction ->
                val snapshot = transaction.get(userRef)

                // De-dup: danes že zabeležen kot WORKOUT_DONE → preskoči
                @Suppress("UNCHECKED_CAST")
                val dailyHistory = (snapshot.get("dailyHistory") as? Map<String, Any>) ?: emptyMap()
                if (dailyHistory[todayStr] == "WORKOUT_DONE") {
                    Log.d("GamificationRepo", "processWorkoutCompletion: danes že WORKOUT_DONE — preskočim.")
                    return@runTransaction null
                }

                val oldStreak    = (snapshot.getLong("streak_days")        ?: 0L).toInt()
                val oldLastEpoch =  snapshot.getLong("last_workout_epoch") ?: 0L
                val oldPlanDay   = (snapshot.getLong("plan_day")           ?: 1L).toInt()
                val oldFreezes   = (snapshot.getLong("streak_freezes")     ?: 0L).toInt()

                // Plan day: +1 samo za redne workouty
                val newPlanDay = if (incrementPlanDay) oldPlanDay + 1 else oldPlanDay

                // Epoch-based streak izračun z Streak Freeze podporo
                val dayDiff = todayEpoch - oldLastEpoch
                var newFreezes = oldFreezes
                val newStreak = when {
                    oldLastEpoch == 0L -> 1              // prvi trening kdajkoli
                    dayDiff == 0L      -> oldStreak      // danes že treniral (via drug update) — ohrani
                    dayDiff == 1L      -> oldStreak + 1  // včeraj → podaljšaj
                    else -> {
                        // Prekinitev — preveri zamrznitve (Streak Freeze)
                        if (oldFreezes > 0) {
                            newFreezes = oldFreezes - 1
                            Log.d("GamificationRepo", "❄️ Streak Freeze porabljen! Ostalo: $newFreezes")
                            oldStreak  // streak se ohrani, NE poveča
                        } else {
                            1          // ni zamrznitev → ponastavi na 1
                        }
                    }
                }

                val updates = mutableMapOf<String, Any>(
                    "streak_days"              to newStreak,
                    "plan_day"                 to newPlanDay,
                    "last_workout_epoch"       to todayEpoch,
                    "last_streak_update_date"  to todayStr,
                    "dailyHistory.$todayStr"   to "WORKOUT_DONE"
                )
                if (newFreezes != oldFreezes) {
                    updates["streak_freezes"] = newFreezes
                }

                transaction.update(userRef, updates)
                Log.d("GamificationRepo", "✅ processWorkoutCompletion: streak=$newStreak, planDay=$newPlanDay, " +
                    "incrementPlanDay=$incrementPlanDay, freezeUsed=${newFreezes != oldFreezes}")
                null
            }.await()
        } catch (e: Exception) {
            Log.e("GamificationRepo", "❌ processWorkoutCompletion failed: ${e.message}", e)
        }
    }

    /**
     * Vrni status današnjega dne iz dailyHistory mape.
     */
    override suspend fun getTodayStatus(): String? {
        val userRef = FirestoreHelper.getCurrentUserDocRef() ?: return null
        return try {
            val snapshot = userRef.get().await()
            @Suppress("UNCHECKED_CAST")
            val dailyHistory = (snapshot.get("dailyHistory") as? Map<String, Any>) ?: emptyMap()
            dailyHistory[getTodayStr()]?.toString()
        } catch (e: Exception) {
            Log.e("GamificationRepo", "getTodayStatus failed", e)
            null
        }
    }

    override suspend fun consumeStreakFreeze(): Boolean {
        val userRef = FirestoreHelper.getCurrentUserDocRef() ?: return false
        return try {
            var freezeConsumed = false
            db.runTransaction { transaction ->
                val snapshot = transaction.get(userRef)
                val currentFreezes = snapshot.getLong("streak_freezes")?.toInt() ?: 0

                if (currentFreezes > 0) {
                    transaction.update(userRef, "streak_freezes", currentFreezes - 1)
                    freezeConsumed = true
                }
            }.await()
            freezeConsumed
        } catch (e: Exception) {
             false
        }
    }

    /**
     * Faza 4b — Polnočni streak check (brez auto-swap logike).
     *
     * Pravila:
     * - Dan je zabeležen v dailyHistory mapi → ni akcije.
     * - Dan ni zabeležen + ima freeze → auto-porabi freeze, zapiši "FROZEN".
     * - Dan ni zabeležen + ni freeze → streak = 0, zapiši "MISSED".
     *
     * checkIfFutureRestDaysExistAndSwap() je IZBRISAN (Faza 4b).
     */
    /**
     * Zapiši porabljene kalorije v dailyLogs/{todayStr}.burnedCalories (atomarna transakcija).
     * Kličejo jo domain use cases (ManageGamificationUseCase) brez direktnega dostopa do DailyLogRepository.
     */
    override suspend fun logBurnedCalories(todayStr: String, calories: Double) {
        try {
            val userRef = FirestoreHelper.getCurrentUserDocRef() ?: return
            val db = FirestoreHelper.getDb()
            val dailyLogRef = db.collection("dailyLogs").document(todayStr)
            db.runTransaction { transaction ->
                val snapshot = transaction.get(dailyLogRef)
                val existing = (snapshot.get("burnedCalories") as? Number)?.toDouble() ?: 0.0
                transaction.set(dailyLogRef,
                    mapOf("burnedCalories" to existing + calories,
                          "userId" to (userRef.id)),
                    SetOptions.merge()
                )
                null
            }.await()
        } catch (e: Exception) {
            Log.e("GamificationRepo", "logBurnedCalories failed: ${e.message}")
        }
    }

    /**
     * Vrni GamificationState (weeklyTarget, workoutDoneToday) iz Firestore.
     * Nadomešča workoutDoneProvider/weeklyTargetProvider lambda-je.
     */
    override suspend fun getGamificationState(): GamificationState {
        return try {
            val userRef = FirestoreHelper.getCurrentUserDocRef() ?: return GamificationState()
            val snapshot = userRef.get().await()
            val weeklyTarget = snapshot.getLong("weekly_target")?.toInt() ?: 0
            val todayStatus = getTodayStatus() ?: ""
            val workoutDoneToday = todayStatus == "WORKOUT_DONE" || todayStatus == "STRETCHING_DONE"
            GamificationState(weeklyTarget = weeklyTarget, workoutDoneToday = workoutDoneToday)
        } catch (e: Exception) {
            GamificationState()
        }
    }

    override suspend fun runMidnightStreakCheck() {
        val userRef = FirestoreHelper.getCurrentUserDocRef() ?: return
        val yesterdayStr = getYesterdayStr()

        try {
            db.runTransaction { transaction ->
                val snapshot = transaction.get(userRef)

                // Preveri dailyHistory mapo v glavnem dokumentu
                @Suppress("UNCHECKED_CAST")
                val dailyHistory = (snapshot.get("dailyHistory") as? Map<String, Any>) ?: emptyMap()

                if (dailyHistory.containsKey(yesterdayStr)) {
                    // Včeraj je bil uspešno zabeležen — ni akcije
                    Log.d("GamificationRepo", "Včeraj ($yesterdayStr) zabeležen: ${dailyHistory[yesterdayStr]}")
                    return@runTransaction null
                }

                // Včerajšnji dan ni bil opravljen
                val currentFreezes = (snapshot.getLong("streak_freezes") ?: 0L).toInt()

                if (currentFreezes > 0) {
                    // Auto-porabi Streak Freeze
                    transaction.update(userRef, mapOf(
                        "streak_freezes" to (currentFreezes - 1),
                        "dailyHistory.$yesterdayStr" to "FROZEN"
                    ))
                    Log.d("GamificationRepo", "❄️ Streak Freeze auto-porabljen. Ostalo: ${currentFreezes - 1}")
                } else {
                    // Ni freeze-a → streak pade na 0
                    transaction.update(userRef, mapOf(
                        "streak_days" to 0,
                        "dailyHistory.$yesterdayStr" to "MISSED"
                    ))
                    Log.d("GamificationRepo", " Ni freeze-a. Streak je padel na 0.")
                }
                null
            }.await()
        } catch (e: Exception) {
            Log.e("GamificationRepo", "Polnočni streak check je spodletel.", e)
        }
    }

}

package com.example.myapplication.data.gamification

import android.content.Context
import com.example.myapplication.domain.gamification.ManageGamificationUseCase

/**
 * GamificationFactory — composition root za ManageGamificationUseCase.
 *
 * Pravilna lokacija: data/ sloj (factory sme imeti dostop do concrete implementacij).
 * Nadomešča domain/gamification/GamificationProvider (ki je bil v napačnem sloju).
 *
 * Singleton pattern: isti UseCase za celo aplikacijo (Firestore listener-ji se ne podvoijo).
 */
object GamificationFactory {
    @Volatile
    private var instance: ManageGamificationUseCase? = null

    fun provide(@Suppress("UNUSED_PARAMETER") context: Context): ManageGamificationUseCase {
        return instance ?: synchronized(this) {
            instance ?: ManageGamificationUseCase(
                repository = FirestoreGamificationRepository()
            ).also { instance = it }
        }
    }
}

package com.example.myapplication.data.workout
import com.example.myapplication.data.settings.UserPreferencesRepository import com.example.myapplication.domain.workout.WorkoutStats import com.example.myapplication.domain.workout.WorkoutStatsRepository import com.example.myapplication.persistence.FirestoreHelper import kotlinx.coroutines.tasks.await import kotlinx.datetime.Clock import kotlinx.datetime.TimeZone import kotlinx.datetime.toLocalDateTime
/** * Data-layer implementacija WorkoutStatsRepository. * * Bere podatke iz Firestore (prek FirestoreHelper) in lokalne SharedPrefs (fallback). * Wrappira UserProfileManager.getWorkoutStats() logiko v domenski interface. * * todayIsRest je vedno false — ViewModel izračuna isRestDay iz plan modela * (ki je presentation concern, ne domenski concern). * * @param prefs UserPreferencesRepository za lokalni fallback (SharedPrefs) */ class UserWorkoutStatsRepository( private val prefs: UserPreferencesRepository ) : WorkoutStatsRepository {
override suspend fun getWorkoutStats(email: String): WorkoutStats? { return try { val docRef = FirestoreHelper.getCurrentUserDocRef() ?: return null val doc = docRef.get().await() if (!doc.exists()) return null
val todayStr = Clock.System.now() .toLocalDateTime(TimeZone.currentSystemDefault()).date.toString()
@Suppress("UNCHECKED_CAST") val dailyHistory = (doc.get("dailyHistory") as? Map<String, Any>) ?: emptyMap() val todayStatus = dailyHistory[todayStr]?.toString() ?: ""
WorkoutStats( streakDays = doc.getLong("streak_days")?.toInt() ?: 0, streakFreezes = doc.getLong("streak_freezes")?.toInt() ?: 0, weeklyDone = doc.getLong("weekly_done")?.toInt() ?: 0, weeklyTarget = doc.getLong("weekly_target")?.toInt() ?: 3, planDay = doc.getLong("plan_day")?.toInt() ?: 1, totalWorkoutsCompleted = doc.getLong("total_workouts_completed")?.toInt() ?: 0, lastWorkoutEpoch = doc.getLong("last_workout_epoch") ?: 0L, todayStatus = todayStatus, todayIsRest = false, // ViewModel izračuna iz plan modela dailyKcal = prefs.getDailyCalories().toInt() ) } catch (e: Exception) { null } }
override suspend fun isWorkoutDoneToday(): Boolean = prefs.isWorkoutDoneToday()
override suspend fun getPlanDay(): Int = prefs.getPlanDay()
override suspend fun getDailyCalories(): Int = prefs.getDailyCalories().toInt() }

package com.example.myapplication.domain.gamification

import android.content.Context
import com.example.myapplication.data.gamification.FirestoreGamificationRepository
import com.example.myapplication.data.settings.UserPreferencesRepository

object GamificationProvider {
    @Volatile
    private var instance: ManageGamificationUseCase? = null

    fun provide(context: Context): ManageGamificationUseCase {
        return instance ?: synchronized(this) {
            instance ?: createUseCase(context).also { instance = it }
        }
    }

    private fun createUseCase(context: Context): ManageGamificationUseCase {
        val repository = FirestoreGamificationRepository()
        val prefs = UserPreferencesRepository(context.applicationContext)
        return ManageGamificationUseCase(
            repository = repository,
            workoutDoneProvider = { prefs.isWorkoutDoneToday() },
            weeklyTargetProvider = { prefs.getWeeklyTargetFlow() }
        )
    }
}

package com.example.myapplication.domain.gamification
/** * Ključni repozitorij za gamification. * * Ta interface se nahaja v DOMAIN sloju (brez Android odvisnosti). * Definira contract "kaj se da narediti glede streaka ali XP-jev" * in zagotavlja SAMO EN Vir Resnice. */ interface GamificationRepository {
/** * Shrani XP (s Firebase batch logiko). * @param amount Količina XP (npr. 10). * @param reason Razlog prejema ("Workout complete", "Daily Login"). */ suspend fun awardXP(amount: Int, reason: String)
/** * Vrni trenutno število streaka iz enotnega vira podatkov. */ suspend fun getCurrentStreak(): Int
/** * Povečaj ali ohrani streak. Zažene se, ko je uspešno zabeleženo, * in pod kapuco reši tisti "Heisenbug". * @param isWorkoutSuccess Je bil trening ali rest day uspešno obkljukan danes? * @param activityType Tip aktivnosti za dailyHistory mapo: "WORKOUT_DONE" ali "STRETCHING_DONE" * @return Novi streak po posodobitvi (0 ob napaki) */ suspend fun updateStreak(isWorkoutSuccess: Boolean, activityType: String = "WORKOUT_DONE"): Int
/** * Označi TODAY kot "PENDING_STRETCHING" v dailyHistory mapi. * Kliče se, ko app ugotovi da je danes rest day — a uporabnik * še NI opravil raztezanja. Status ne pripiše streak +1. * Prehod v "STRETCHING_DONE" se zgodi SAMO prek [updateStreak] ob * eksplicitni uporabnikovi akciji. * * ⛔ runMidnightCheck() NE sme klicati te metode — polnočni check * preverja VČERAJ (ne danes) in ne sme avtokonkludirati rest dnevov. */ suspend fun markRestDayPending()
/** * Ozadičen worker (polnoč) reče repositoryju: "Preveri in resetiraj, če manjkajo workouti". * ⚠️ Ta metoda analizira SAMO VČERAJŠNJI dan — nikoli ne auto-complete todayja. */ suspend fun runMidnightStreakCheck()
/** * Za uporabo Streak Freeze, če je na voljo. */ suspend fun consumeStreakFreeze(): Boolean
/** * Faza 8 — Unified Streak Engine. * NADOMEŠČA UserProfileManager.updateUserProgressAfterWorkout(). * * V ENI Firestore transakciji: * - Epoch-based streak izračun (dayDiff z Streak Freeze podporo) * - Zapiše dailyHistory.$today = "WORKOUT_DONE" * - Posodobi streak_days, last_workout_epoch, plan_day * * iOS-ready: vsa logika v domain/data layer, brez Android odvisnosti. * * @param incrementPlanDay true za redne workouty, false za extra treninge */ suspend fun processWorkoutCompletion(incrementPlanDay: Boolean)
/** * Vrni status današnjega dne iz dailyHistory mape. * Možne vrednosti: "WORKOUT_DONE", "STRETCHING_DONE", "PENDING_STRETCHING", * "FROZEN", "MISSED", ali null (dan ni bil zabeležen). */ suspend fun getTodayStatus(): String? }

