/** * Shrani XP (s Firebase batch logiko). * @param amount Količina XP (npr. 10). * @param reason Razlog prejema ("Workout complete", "Daily Login"). */ suspend fun awardXP(amount: Int, reason: String)
/** * Vrni trenutno število streaka iz enotnega vira podatkov. */ suspend fun getCurrentStreak(): Int
